// Spare Parts Stock Signal Calculator
// Processes inventory data and flags parts needing attention

const items = $input.all();
const today = new Date();

const alerts = [];
const healthy = [];

for (const item of items) {
  const data = item.json;

  // Parse numeric fields (Google Sheets returns strings)
  const currentStock = parseFloat(data.current_stock) || 0;
  const reorderThreshold = parseFloat(data.reorder_threshold) || 0;
  const dailyConsumption = parseFloat(data.daily_consumption_avg) || 0;
  const leadTimeDays = parseFloat(data.supplier_lead_time_days) || 0;
  const unitCost = parseFloat(data.unit_cost_eur) || 0;

  // Calculate derived metrics
  const daysOfStockLeft = dailyConsumption > 0
    ? Math.round(currentStock / dailyConsumption)
    : 999; // If no consumption, effectively infinite

  const stockCoversDuringLeadTime = daysOfStockLeft >= leadTimeDays;
  const stockAboveThreshold = currentStock >= reorderThreshold;
  const demandDuringLeadTime = Math.round(dailyConsumption * leadTimeDays);
  const suggestedOrderQty = Math.max(0, reorderThreshold - currentStock + demandDuringLeadTime);
  const estimatedOrderCost = Math.round(suggestedOrderQty * unitCost);

  // Calculate days since last restock
  const lastRestock = new Date(data.last_restock_date);
  const daysSinceRestock = Math.round((today - lastRestock) / (1000 * 60 * 60 * 24));

  // Determine severity
  let severity = 'OK';
  let reason = '';

  if (currentStock <= 0) {
    severity = 'STOCKOUT';
    reason = 'No stock remaining — immediate action required';
  } else if (!stockAboveThreshold && !stockCoversDuringLeadTime) {
    severity = 'CRITICAL';
    reason = `Below reorder threshold AND stock will run out before supplier can deliver (${daysOfStockLeft} days left vs ${leadTimeDays}-day lead time)`;
  } else if (!stockAboveThreshold) {
    severity = 'WARNING';
    reason = `Below reorder threshold (${currentStock} vs ${reorderThreshold} minimum)`;
  } else if (daysOfStockLeft <= leadTimeDays * 1.5) {
    severity = 'WATCH';
    reason = `Approaching reorder point — ${daysOfStockLeft} days of stock remaining`;
  }

  const enrichedPart = {
    part_id: data.part_id,
    part_name: data.part_name,
    category: data.category,
    depot: data.depot,
    current_stock: currentStock,
    reorder_threshold: reorderThreshold,
    daily_consumption_avg: dailyConsumption,
    days_of_stock_left: daysOfStockLeft,
    supplier_lead_time_days: leadTimeDays,
    stock_covers_lead_time: stockCoversDuringLeadTime,
    severity: severity,
    reason: reason,
    suggested_order_qty: suggestedOrderQty,
    estimated_order_cost_eur: estimatedOrderCost,
    days_since_last_restock: daysSinceRestock,
    unit_cost_eur: unitCost
  };

  if (severity !== 'OK') {
    alerts.push(enrichedPart);
  } else {
    healthy.push(enrichedPart);
  }
}

// Sort alerts: STOCKOUT first, then CRITICAL, then WARNING, then WATCH
const severityOrder = { 'STOCKOUT': 0, 'CRITICAL': 1, 'WARNING': 2, 'WATCH': 3 };
alerts.sort((a, b) => severityOrder[a.severity] - severityOrder[b.severity]);

// Build a summary object for the LLM prompt
const summary = {
  report_date: today.toISOString().split('T')[0],
  total_parts_monitored: items.length,
  alerts_count: alerts.length,
  healthy_count: healthy.length,
  critical_count: alerts.filter(a => a.severity === 'CRITICAL' || a.severity === 'STOCKOUT').length,
  total_estimated_reorder_cost: alerts.reduce((sum, a) => sum + a.estimated_order_cost_eur, 0),
  alerts: alerts,
  depots_affected: [...new Set(alerts.map(a => a.depot))]
};

return [{ json: summary }];

